<?php
declare(strict_types=1);
require dirname(__DIR__).'/bootstrap.php';
$admin=vp3_require_admin_permission('network.manage');$id=(int)vp3_input('id');
if(vp3_method()==='POST'){vp3_verify_csrf();$customerId=(int)vp3_input('customer_id');$creatorId=(int)vp3_input('creator_id');$title=vp3_input('title');$slug=preg_replace('/[^a-z0-9-]/','',strtolower(vp3_input('slug')))?:'';if($customerId<1||$title===''||$slug===''){vp3_flash('error','Customer, title, and slug are required.');vp3_redirect('admin/show.php'.($id?'?id='.$id:''));}$data=[$customerId,$title,$slug,vp3_input('short_description'),vp3_input('description'),vp3_input('show_type'),vp3_input('genre'),vp3_input('cover_url'),vp3_input('hero_url'),vp3_input('destination_url'),vp3_input('status'),vp3_input('verification_status'),max(0,(int)vp3_input('featured_rank')),vp3_input('launched_at')?:null];if($id>0){$stmt=vp3_db()->prepare('UPDATE shows SET customer_id=?,title=?,slug=?,short_description=?,description=?,show_type=?,genre=?,cover_url=NULLIF(?,\'\'),hero_url=NULLIF(?,\'\'),destination_url=NULLIF(?,\'\'),status=?,verification_status=?,featured_rank=?,launched_at=?,updated_at=NOW() WHERE id=?');$stmt->execute([...$data,$id]);$uuid=(string)vp3_db()->query('SELECT show_uuid FROM shows WHERE id='.(int)$id)->fetchColumn();}else{$uuid=vp3_uuid();$stmt=vp3_db()->prepare('INSERT INTO shows (show_uuid,customer_id,title,slug,short_description,description,show_type,genre,cover_url,hero_url,destination_url,status,verification_status,featured_rank,launched_at,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,NULLIF(?,\'\'),NULLIF(?,\'\'),NULLIF(?,\'\'),?,?,?,?,NOW(),NOW())');$stmt->execute([$uuid,...$data]);$id=(int)vp3_db()->lastInsertId();}vp3_db()->prepare('DELETE FROM show_creators WHERE show_id=? AND is_primary=1')->execute([$id]);if($creatorId>0){$owner=vp3_db()->prepare('SELECT id FROM creators WHERE id=? AND customer_id=?');$owner->execute([$creatorId,$customerId]);if(!$owner->fetchColumn())throw new RuntimeException('creator_customer_mismatch');vp3_db()->prepare('INSERT INTO show_creators(show_id,creator_id,role_name,is_primary,sort_order,created_at) VALUES (?,?,\'Creator\',1,0,NOW())')->execute([$id,$creatorId]);}vp3_audit('admin',(int)$admin['id'],'show.saved','show',$uuid,['id'=>$id]);vp3_flash('success','Show saved.');vp3_redirect('admin/show.php?id='.$id);}
$row=null;if($id>0){$s=vp3_db()->prepare('SELECT s.*,sc.creator_id FROM shows s LEFT JOIN show_creators sc ON sc.show_id=s.id AND sc.is_primary=1 WHERE s.id=?');$s->execute([$id]);$row=$s->fetch();if(!$row){http_response_code(404);exit('Show not found.');}}
$customers=vp3_db()->query("SELECT id,name,email FROM customers WHERE status IN ('active','pending') ORDER BY name")->fetchAll();$creators=vp3_db()->query("SELECT id,customer_id,display_name FROM creators ORDER BY display_name")->fetchAll();$pageTitle=$row?'Edit Show':'Add Show';require VP3_ROOT.'/includes/admin-header.php';
?>
<div class="admin-page-head"><div><span class="admin-kicker">VP3 Network</span><h1><?=vp3_e($pageTitle)?></h1></div><a class="button secondary" href="shows.php">Back to shows</a></div><form class="card admin-form" method="post"><?=vp3_csrf_field()?><div class="admin-form-grid"><div class="field"><label>Customer</label><select name="customer_id" required><option value="">Select</option><?php foreach($customers as $c):?><option value="<?=(int)$c['id']?>" <?= (int)($row['customer_id']??0)===(int)$c['id']?'selected':'' ?>><?=vp3_e($c['name'].' · '.$c['email'])?></option><?php endforeach;?></select></div><div class="field"><label>Primary creator</label><select name="creator_id"><option value="0">Unassigned</option><?php foreach($creators as $c):?><option value="<?=(int)$c['id']?>" <?= (int)($row['creator_id']??0)===(int)$c['id']?'selected':'' ?>><?=vp3_e($c['display_name'])?></option><?php endforeach;?></select></div><div class="field"><label>Title</label><input name="title" value="<?=vp3_e($row['title']??'')?>" required></div><div class="field"><label>Slug</label><input name="slug" value="<?=vp3_e($row['slug']??'')?>" pattern="[a-z0-9-]+" required></div><div class="field full"><label>Short description</label><input name="short_description" value="<?=vp3_e($row['short_description']??'')?>"></div><div class="field full"><label>Full description</label><textarea name="description"><?=vp3_e($row['description']??'')?></textarea></div><div class="field"><label>Show type</label><select name="show_type"><?php foreach(['scripted_series','microdrama','reality','podcast','music_series','documentary','live_event','mixed_media'] as $v):?><option <?=($row['show_type']??'scripted_series')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Genre</label><input name="genre" value="<?=vp3_e($row['genre']??'')?>"></div><div class="field"><label>Cover URL</label><input name="cover_url" type="url" value="<?=vp3_e($row['cover_url']??'')?>"></div><div class="field"><label>Hero URL</label><input name="hero_url" type="url" value="<?=vp3_e($row['hero_url']??'')?>"></div><div class="field"><label>Official destination</label><input name="destination_url" type="url" value="<?=vp3_e($row['destination_url']??'')?>"></div><div class="field"><label>Status</label><select name="status"><?php foreach(['draft','published','archived'] as $v):?><option <?=($row['status']??'draft')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Verification</label><select name="verification_status"><?php foreach(['pending','verified','rejected','suspended'] as $v):?><option <?=($row['verification_status']??'pending')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Featured rank</label><input name="featured_rank" type="number" min="0" value="<?=vp3_e($row['featured_rank']??0)?>"></div><div class="field"><label>Launch date</label><input name="launched_at" type="date" value="<?=vp3_e(isset($row['launched_at'])?substr((string)$row['launched_at'],0,10):'')?>"></div></div><button class="button">Save show</button></form>
<?php require VP3_ROOT.'/includes/admin-footer.php';?>
